import { useEffect, useState } from "react";
import api from "../api";
import "./styles/Books.css";

function HistoryByCategory() {
  const [history, setHistory] = useState({});

  useEffect(() => {
    api.get("/history-by-category")
      .then(res => setHistory(res.data))
      .catch(() => setHistory({}));
  }, []);

  return (
    <div className="books-page">
      <h1 className="books-title">History by Category</h1>

      {Object.keys(history).map((category) => (
        <div key={category} style={{ marginBottom: "40px" }}>
          <h2 style={{ color: "#3b2416", marginBottom: "12px" }}>
            {category}
          </h2>

          {history[category].length === 0 ? (
            <p style={{ color: "#6b3f25" }}>
              No books borrowed in this category.
            </p>
          ) : (
            <ul style={{ color: "#3b2416" }}>
              {history[category].map((book, index) => (
                <li key={index}>{book}</li>
              ))}
            </ul>
          )}
        </div>
      ))}
    </div>
  );
}

export default HistoryByCategory;
